parameters.jsCode:
try {
  // 1. AI ලියපු Text එක ගන්නවා
  const rawText = $input.item.json.content.parts[0].text || $input.item.json.message.content || $input.item.json.text;

  // 2. අර ```json මාර්ක් ටික අයින් කරලා පිරිසිදු කරනවා
  const cleanJson = rawText.replace(/```json/g, '').replace(/```/g, '').trim();
  const aiData = JSON.parse(cleanJson);

  // 3. කලින් Nodes වලින් ආපු අපේ ඇත්ත Data ටික (නම, කම්පැණි එක, Hunter දීපු ඊමේල් එක) ගන්නවා
  // (මෙතන 'Code in JavaScript2' සහ 'HTTP Request' කියන නම් ඔයාගේ ඒ අදාල Nodes වල නම් වලට සමාන වෙන්න ඕනේ)
  const first_name = $node["Code in JavaScript2"].json.first_name || "Unknown";
  const last_name = $node["Code in JavaScript2"].json.last_name || "";
  const company = $node["Code in JavaScript2"].json.company || "Unknown";
  const email = $node["HTTP Request"].json.data.email || "No Email Found";

  // 4. Supabase එකටයි Telegram එකටයි යවන්න ලස්සනට පැකට් එකක් හදනවා
  return {
    lead_name: `${first_name} ${last_name}`.trim(),
    company: company,
    email: email,
    ai_draft: aiData.ai_draft || aiData.body || "Draft Not Generated",
    subject: aiData.subject || "Collaboration Opportunity",
    intent_score: aiData.intent_score || 85
  };

} catch (e) {
  console.log("JSON කඩන එකේ අවුලක්:", e);
  return { error: "Failed to parse AI response" };
}

